// menu.js - كاردات واضحة جداً عند الضغط
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  const [clickedCard, setClickedCard] = useState(null);
  
  const backgroundImageUrl = "https://img.freepik.com/photos-premium/banniere-pour-page-menu-table-cuisine-legumes-epices-ustensiles-fond-sombre-vue-dessus-espace-libre-pour-texte_187166-66331.jpg?semt=ais_hybrid&w=740&q=80";
  
  const texts = ["مرحباً", "أهلاً", "تفضلوا", "استمتعوا"];

  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", gradient: "linear-gradient(135deg, #ff6b6b, #ee5a24)", size: 210, top: "12%", left: "8%", rotate: -8, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", gradient: "linear-gradient(135deg, #4ecdc4, #44bdac)", size: 200, bottom: "12%", left: "10%", rotate: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", gradient: "linear-gradient(135deg, #45b7d1, #3498db)", size: 205, top: "15%", right: "8%", rotate: -6, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", gradient: "linear-gradient(135deg, #f9ca24, #f39c12)", size: 195, bottom: "15%", right: "10%", rotate: 7, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 2800);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 40,
        y: (e.clientY / window.innerHeight - 0.5) * 40
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const handleCardClick = (cardName, cardId) => {
    setClickedCard(cardId);
    alert(`✨ لقد اخترت: ${cardName} ✨`);
    setTimeout(() => setClickedCard(null), 500);
  };

  return (
    <div style={{
      minHeight: "100vh",
      backgroundImage: `url(${backgroundImageUrl})`,
      backgroundSize: "cover",
      backgroundPosition: "center",
      backgroundRepeat: "no-repeat",
      backgroundAttachment: "fixed",
      position: "relative",
      overflow: "hidden",
      fontFamily: "'Cairo', 'Tajawal', sans-serif"
    }}>
      
      {/* طبقة شفافة خفيفة جداً */}
      <div style={{
        position: "absolute",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: "rgba(0,0,0,0.3)",
        pointerEvents: "none",
        zIndex: 1
      }}></div>

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0px) translateX(0px); }
          50% { transform: translateY(-15px) translateX(8px); }
        }
        @keyframes clickPulse {
          0% { transform: scale(1); }
          50% { transform: scale(0.95); box-shadow: 0 0 0 10px rgba(34,197,94,0.8); }
          100% { transform: scale(1); }
        }
        @keyframes glow {
          0%, 100% { text-shadow: 0 0 20px rgba(34,197,94,0.6); }
          50% { text-shadow: 0 0 50px rgba(34,197,94,0.9); }
        }
      `}</style>

      {/* الكاردات */}
      {cards.map((card) => (
        <div
          key={card.id}
          onClick={() => handleCardClick(card.name, card.id)}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            bottom: card.bottom,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.5 : -0.4)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.4 : 0.5)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.2s ease-out",
            zIndex: 15,
            cursor: "pointer",
            animation: `float ${3 + card.id * 0.5}s infinite ease-in-out`,
            animationDelay: `${card.id * 0.2}s`
          }}
        >
          <div style={{
            background: card.gradient,
            width: `${card.size}px`,
            padding: "35px 20px",
            borderRadius: "50px",
            textAlign: "center",
            boxShadow: clickedCard === card.id 
              ? "0 0 0 6px #22c55e, 0 0 0 12px rgba(34,197,94,0.4), 0 30px 60px rgba(0,0,0,0.6)" 
              : "0 25px 45px rgba(0,0,0,0.4), 0 0 0 2px rgba(255,255,255,0.2) inset",
            backdropFilter: "blur(10px)",
            transition: "all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)",
            transform: clickedCard === card.id ? "scale(1.05)" : "scale(1)",
            border: clickedCard === card.id ? "2px solid #22c55e" : "none",
            cursor: "pointer"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.12) rotate(${card.rotate + 10}deg)`;
            e.currentTarget.style.boxShadow = "0 35px 60px rgba(0,0,0,0.5), 0 0 0 3px rgba(34,197,94,0.5) inset";
          }}
          onMouseLeave={(e) => {
            if (clickedCard !== card.id) {
              e.currentTarget.style.transform = "scale(1) rotate(0deg)";
              e.currentTarget.style.boxShadow = "0 25px 45px rgba(0,0,0,0.4), 0 0 0 2px rgba(255,255,255,0.2) inset";
            }
          }}
          >
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: "90px", 
                height: "90px", 
                marginBottom: "15px", 
                filter: "drop-shadow(0 8px 20px rgba(0,0,0,0.3))",
                transition: "transform 0.3s"
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "12px 0 8px", 
              fontSize: "1.9rem", 
              fontWeight: "bold",
              textShadow: "0 2px 5px rgba(0,0,0,0.3)",
              letterSpacing: "1px"
            }}>{card.name}</h3>
            <span style={{ fontSize: "3rem", filter: "drop-shadow(0 2px 5px rgba(0,0,0,0.3))" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* الكلمة المركزية */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.15}px, ${mousePosition.y * 0.15}px)`,
        textAlign: "center",
        zIndex: 25,
        transition: "transform 0.15s ease-out",
        pointerEvents: "none"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.5)",
          backdropFilter: "blur(20px)",
          padding: "45px 85px",
          borderRadius: "90px",
          border: "2px solid rgba(34,197,94,0.5)",
          boxShadow: "0 0 70px rgba(34,197,94,0.25), 0 20px 40px rgba(0,0,0,0.3)"
        }}>
          <h1 style={{
            fontSize: "6rem",
            fontWeight: "900",
            background: "linear-gradient(135deg, #22c55e, #4ade80)",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            margin: 0,
            letterSpacing: "6px",
            animation: "glow 2.5s infinite"
          }}>
            {texts[textIndex]}
          </h1>
          <div style={{
            width: "160px",
            height: "3px",
            background: "linear-gradient(90deg, transparent, #22c55e, #4ade80, #22c55e, transparent)",
            margin: "25px auto 0",
            borderRadius: "10px"
          }}></div>
        </div>
      </div>

      {/* شريط سفلي واضح */}
      <div style={{
        position: "fixed",
        bottom: "25px",
        left: "50%",
        transform: "translateX(-50%)",
        textAlign: "center",
        zIndex: 30,
        pointerEvents: "none"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.7)",
          backdropFilter: "blur(15px)",
          padding: "10px 28px",
          borderRadius: "50px",
          border: "1px solid #22c55e",
          boxShadow: "0 0 20px rgba(34,197,94,0.3)"
        }}>
          <span style={{ color: "#22c55e", fontSize: "14px", fontWeight: "bold" }}>✦</span>
          <span style={{ color: "white", fontSize: "14px", letterSpacing: "1px", margin: "0 12px" }}>اضغط على أي كارد</span>
          <span style={{ color: "#22c55e", fontSize: "14px", fontWeight: "bold" }}>✦</span>
        </div>
      </div>
    </div>
  );
}
